function solve(nums) {
    const n = nums.length;
    if (n === 0) return 0;

    const maxSpf = 1000000;
    const spf = new Array(maxSpf + 1).fill(0);

    for (let i = 2; i <= maxSpf; i++) {
        if (spf[i] === 0) {
            spf[i] = i;
            for (let j = i * 2; j <= maxSpf; j += i) {
                if (spf[j] === 0) {
                    spf[j] = i;
                }
            }
        }
    }

    const primeToIndices = new Map();

    for (let i = 0; i < n; i++) {
        const num = nums[i];
        if (num < 2) continue;

        let x = num;
        const primes = new Set();

        while (x > 1) {
            const p = spf[x];
            primes.add(p);
            while (x % p === 0) {
                x /= p;
            }
        }

        for (const p of primes) {
            if (!primeToIndices.has(p)) {
                primeToIndices.set(p, []);
            }
            primeToIndices.get(p).push(i);
        }
    }

    const dist = new Array(n).fill(-1);
    const queue = [0];
    dist[0] = 0;

    while (queue.length > 0) {
        const i = queue.shift();
        if (i === n - 1) return dist[i];

        for (const next of [i - 1, i + 1]) {
            if (next >= 0 && next < n && dist[next] === -1) {
                dist[next] = dist[i] + 1;
                queue.push(next);
            }
        }

        const currentNum = nums[i];
        if (currentNum >= 2 && spf[currentNum] === currentNum) {
            const list = primeToIndices.get(currentNum);
            if (list) {
                for (const j of list) {
                    if (j !== i && dist[j] === -1) {
                        dist[j] = dist[i] + 1;
                        queue.push(j);
                    }
                }
            }
        }
    }

    return -1;
}
